+    fn decode_binary(data: &[u8]) -> Result<Self, Error> {
+        if data.len() != 16 {
+            return Err(binary_length_error("uuid", 16, data.len()));
+        }
+        let mut bytes = [0u8; 16];
+        bytes.copy_from_slice(data);
+        Ok(bytes)
+    }
